      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  changeLookupReadonly(f, 'ma_dvcs');
  if (!f.getItemValue('nam')) f.getItem('nam').value = (new Date()).getFullYear();
  f.live(f.getItem('thang1'));
}
function close$VoucherFilter$(sender) {try {sender.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid;
      var t1 = f.getItemValue('thang1'), t2 = f.getItemValue('thang2');
      g._alterTitle = [null, [['%t1', t1, true], ['%t2', t2, true], ['%y', f.getItemValue('nam'), true]]];

      var c = t1 + String.fromCharCode(255) + t2 + String.fromCharCode(255) + f.getItemValue('mau_bc');
      if (!g._v) g._v = c;
      if (g._v != c) {
        remove$GridReport$Filter(g);
        g._v = c;
      }
      break;
    default:
      break;
  }
}
function initForm(f) {
  var o = f.getItem('form'), value = f._itemValue.split(String.fromCharCode(255)), text = f._itemText.split(String.fromCharCode(255));
  for (var i = 0; i < value.length; i++) {
    o.options[i] = new Option(text[i], value[i]);
  }
}
